import Foundation
import Testing

// MARK: - R15(c) — sqlite-vec KNN p50/p95/p99 fixture bridge
//
// The authoritative PR4 baseline is generated by the Rust integration test:
//   cargo test --manifest-path epistemos-core/Cargo.toml \
//     --test sqlite_vec_knn_baseline -- --ignored --nocapture
//
// This disabled Swift suite verifies the committed report contract and prevents
// the old sleep-based stub from being mistaken for a real benchmark.
// Run manually:
//   xcodebuild test -scheme Epistemos \
//     -only-testing:EpistemosTests/SQLiteVecKNNBenchTests

private let sqliteVecKNNBaselineFilename =
    "2026-05-01t00-00-00-000z-r15-sqlite-vec-knn-sqlite_vec_knn_100k_32d.json"

@Suite("sqlite-vec KNN", .disabled("Manual bridge to the Rust sqlite-vec fixture baseline"))
struct SQLiteVecKNNBenchTests {

    @Test func rustFixtureBaselineReportIsAvailable() throws {
        let report = try loadPR4BaselineReport()

        #expect(report.schema_version == 1)
        #expect(report.suite == "sqlite-vec KNN")
        #expect(report.measurement == "sqlite_vec_knn_100k_32d")
        #expect(report.unit == "seconds")
        #expect(report.sample_count == 16)
        #expect(report.metadata["status"] == "real sqlite-vec vec0 KNN fixture")
        #expect(report.metadata["target_vector_count"] == "100000")
        #expect(report.metadata["dimensions"] == "32")
        #expect(report.metadata["query_shape"] == "embedding MATCH ? AND k = ? ORDER BY distance")
        let samplesAreFinite = report.samples.allSatisfy { $0.isFinite }
        #expect(samplesAreFinite)
        #expect(report.p95.isFinite)
        #expect(report.p95 < 0.05)
    }

    private func loadPR4BaselineReport() throws -> BenchmarkRunReport {
        let reportURL = repoRoot()
            .appendingPathComponent("benchmarks", isDirectory: true)
            .appendingPathComponent("results", isDirectory: true)
            .appendingPathComponent(sqliteVecKNNBaselineFilename, isDirectory: false)
        let data = try Data(contentsOf: reportURL)
        return try JSONDecoder().decode(BenchmarkRunReport.self, from: data)
    }

    private func repoRoot() -> URL {
        URL(fileURLWithPath: #filePath)
            .deletingLastPathComponent()
            .deletingLastPathComponent()
            .deletingLastPathComponent()
    }
}
